public int active()
{
    InventDim   inventDim;
    int ret;
    FormDatasource     InventDim_Ds;

    ret =  next Active();
    InventDim_Ds = this;


    if(!ETGcanadaparameters::find().EnableExcludeCustomizations)
    {
        InventDim_Ds.object(fieldNum(InventDim,InventLocationId)).allowEdit(false);
        InventDim_Ds.object(fieldNum(InventDim,inventbatchid)).mandatory(true);
    }


    return ret;
}
